package com.hospital.management.dao.impl;import com.hospital.management.dao.DoctorScheduleDao;import com.hospital.management.model.*;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.time.*;import java.time.format.DateTimeFormatter;import java.util.*;
/** Oracle JDBC schedule persistence with bound filters and SQL overlap detection. */public class DoctorScheduleDaoImpl implements DoctorScheduleDao{private static final DateTimeFormatter T=DateTimeFormatter.ofPattern("HH:mm");private static final String C="s.SCHEDULE_ID,s.DOCTOR_ID,d.DEPARTMENT_ID,d.FIRST_NAME||' '||d.LAST_NAME AS DOCTOR_NAME,dep.DEPARTMENT_NAME,s.DAY_OF_WEEK,s.START_TIME,s.END_TIME,s.SLOT_DURATION_MINUTES,s.IS_AVAILABLE,s.CREATED_AT,s.UPDATED_AT ",F=" FROM DOCTOR_SCHEDULES s JOIN DOCTORS d ON d.DOCTOR_ID=s.DOCTOR_ID JOIN USERS u ON u.USER_ID=d.USER_ID JOIN DEPARTMENTS dep ON dep.DEPARTMENT_ID=d.DEPARTMENT_ID ",W=" WHERE (? IS NULL OR UPPER(d.FIRST_NAME||' '||d.LAST_NAME) LIKE ? ESCAPE '\\' OR UPPER(d.REGISTRATION_NUMBER) LIKE ? ESCAPE '\\' OR UPPER(dep.DEPARTMENT_NAME) LIKE ? ESCAPE '\\' OR UPPER(d.SPECIALIZATION) LIKE ? ESCAPE '\\' OR UPPER(s.DAY_OF_WEEK) LIKE ? ESCAPE '\\') AND (? IS NULL OR s.DOCTOR_ID=?) AND (? IS NULL OR d.DEPARTMENT_ID=?) AND (? IS NULL OR s.DAY_OF_WEEK=?) AND (? IS NULL OR s.IS_AVAILABLE=?) ";
 public Optional<DoctorSchedule> findById(Long id)throws SQLException{if(id==null)return Optional.empty();try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement p=c.prepareStatement("SELECT "+C+F+" WHERE s.SCHEDULE_ID=?")){p.setLong(1,id);try(ResultSet r=p.executeQuery()){return r.next()?Optional.of(map(r)):Optional.empty();}}}public Page<DoctorSchedule> findAll(PageRequest q,Long did,Long dep,String day,Boolean av)throws SQLException{List<DoctorSchedule>x=new ArrayList<>();String sql="SELECT "+C+F+W+" ORDER BY d.FIRST_NAME,d.LAST_NAME,CASE s.DAY_OF_WEEK WHEN 'MONDAY' THEN 1 WHEN 'TUESDAY' THEN 2 WHEN 'WEDNESDAY' THEN 3 WHEN 'THURSDAY' THEN 4 WHEN 'FRIDAY' THEN 5 WHEN 'SATURDAY' THEN 6 ELSE 7 END,s.START_TIME OFFSET ? ROWS FETCH NEXT ? ROWS ONLY";try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement p=c.prepareStatement(sql)){int i=bind(p,q.getSearchTerm(),did,dep,day,av);p.setInt(i++,q.getOffset());p.setInt(i,q.getPageSize());try(ResultSet r=p.executeQuery()){while(r.next())x.add(map(r));}}return new Page<>(x,q.getPageNumber(),q.getPageSize(),count(q.getSearchTerm(),did,dep,day,av));}public long count(String search,Long did,Long dep,String day,Boolean av)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement p=c.prepareStatement("SELECT COUNT(1)"+F+W)){bind(p,search,did,dep,day,av);try(ResultSet r=p.executeQuery()){r.next();return r.getLong(1);}}}
 private int bind(PreparedStatement p,String search,Long did,Long dep,String day,Boolean av)throws SQLException{String s=search==null?"":search.trim(),like="%"+s.toUpperCase().replace("\\","\\\\").replace("%","\\%").replace("_","\\_")+"%";int i=1;p.setString(i++,s.isEmpty()?null:like);for(int n=0;n<5;n++)p.setString(i++,like);i=pair(p,i,did,Types.NUMERIC);i=pair(p,i,dep,Types.NUMERIC);i=pair(p,i,day,Types.VARCHAR);Integer a=av==null?null:av?1:0;return pair(p,i,a,Types.NUMERIC);}private int pair(PreparedStatement p,int i,Object v,int type)throws SQLException{if(v==null)p.setNull(i++,type);else p.setObject(i++,v);if(v==null)p.setNull(i++,type);else p.setObject(i++,v);return i;}
 public long create(DoctorSchedule s)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement p=c.prepareStatement("INSERT INTO DOCTOR_SCHEDULES(DOCTOR_ID,DAY_OF_WEEK,START_TIME,END_TIME,SLOT_DURATION_MINUTES,IS_AVAILABLE)VALUES(?,?,?,?,?,?)",new String[]{"SCHEDULE_ID"})){values(p,s);p.executeUpdate();try(ResultSet k=p.getGeneratedKeys()){if(k.next())return k.getLong(1);}throw new SQLException("No generated schedule identifier returned");}}public boolean update(DoctorSchedule s)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement p=c.prepareStatement("UPDATE DOCTOR_SCHEDULES SET DOCTOR_ID=?,DAY_OF_WEEK=?,START_TIME=?,END_TIME=?,SLOT_DURATION_MINUTES=?,IS_AVAILABLE=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE SCHEDULE_ID=?")){values(p,s);p.setLong(7,s.getScheduleId());return p.executeUpdate()==1;}}private void values(PreparedStatement p,DoctorSchedule s)throws SQLException{p.setLong(1,s.getDoctorId());p.setString(2,s.getDayOfWeek());p.setString(3,s.getStartTime().format(T));p.setString(4,s.getEndTime().format(T));p.setInt(5,s.getSlotDurationMinutes());p.setInt(6,s.isAvailable()?1:0);}public boolean updateAvailability(Long id,boolean a)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement p=c.prepareStatement("UPDATE DOCTOR_SCHEDULES SET IS_AVAILABLE=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE SCHEDULE_ID=?")){p.setInt(1,a?1:0);p.setLong(2,id);return p.executeUpdate()==1;}}
 public boolean existsOverlap(Long d,String day,LocalTime a,LocalTime b)throws SQLException{return overlap(d,day,a,b,null);}public boolean existsOverlapExcludingId(Long d,String day,LocalTime a,LocalTime b,Long id)throws SQLException{return overlap(d,day,a,b,id);}private boolean overlap(Long d,String day,LocalTime a,LocalTime b,Long id)throws SQLException{String sql="SELECT 1 FROM DOCTOR_SCHEDULES WHERE DOCTOR_ID=? AND DAY_OF_WEEK=? AND ? < END_TIME AND ? > START_TIME"+(id==null?"":" AND SCHEDULE_ID<>?")+" FETCH FIRST 1 ROW ONLY";try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement p=c.prepareStatement(sql)){p.setLong(1,d);p.setString(2,day);p.setString(3,a.format(T));p.setString(4,b.format(T));if(id!=null)p.setLong(5,id);try(ResultSet r=p.executeQuery()){return r.next();}}}public List<DoctorSchedule> findAvailableByDoctorAndDay(Long d,String day)throws SQLException{List<DoctorSchedule>x=new ArrayList<>();try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement p=c.prepareStatement("SELECT "+C+F+" WHERE s.DOCTOR_ID=? AND s.DAY_OF_WEEK=? AND s.IS_AVAILABLE=1 ORDER BY s.START_TIME")){p.setLong(1,d);p.setString(2,day);try(ResultSet r=p.executeQuery()){while(r.next())x.add(map(r));}}return x;}private DoctorSchedule map(ResultSet r)throws SQLException{DoctorSchedule s=new DoctorSchedule();s.setScheduleId(r.getLong("SCHEDULE_ID"));s.setDoctorId(r.getLong("DOCTOR_ID"));s.setDepartmentId(r.getLong("DEPARTMENT_ID"));s.setDoctorName(r.getString("DOCTOR_NAME"));s.setDepartmentName(r.getString("DEPARTMENT_NAME"));s.setDayOfWeek(r.getString("DAY_OF_WEEK"));s.setStartTime(LocalTime.parse(r.getString("START_TIME"),T));s.setEndTime(LocalTime.parse(r.getString("END_TIME"),T));s.setSlotDurationMinutes(r.getInt("SLOT_DURATION_MINUTES"));s.setAvailable(r.getInt("IS_AVAILABLE")==1);Timestamp c=r.getTimestamp("CREATED_AT"),u=r.getTimestamp("UPDATED_AT");s.setCreatedAt(c==null?null:c.toLocalDateTime());s.setUpdatedAt(u==null?null:u.toLocalDateTime());return s;}}
